#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* ============================================
 * STRUCTURE DECLARATION AND BASIC USAGE
 * ============================================ */

// Method 1: Traditional struct declaration
struct Student {
 int usn;
 char name[50];
 float percentage;
};

// Method 2: Using typedef for shorter syntax
typedef struct {
 int id;
 char department[30];
 float salary;
} Employee;

// Nested Structure - Date of Birth
struct Date {
 int day;
 int month;
 int year;
};

// Nested Structure - Student with Date
struct StudentWithDOB {
 int usn;
 char name[50];
 struct Date dob; // Nested structure member
 float percentage;
};

// Self-referential structure for Linked List
struct Node {
 int data;
 struct Node *next; // Pointer to same structure type
};

// Union Declaration
union Data {
 int i;
 float f;
 char c;
};

/* ============================================
 * FUNCTION PROTOTYPES
 * ============================================ */
void demonstrateBasicStruct();
void demonstrateNestedStruct();
void demonstrateArrayOfStructures();
void demonstrateLinkedList();
void demonstrateUnion();
void demonstrateStructureVsUnion();

/* ============================================
 * MAIN FUNCTION
 * ============================================ */

int main() {
 printf("==============================================\n");
 printf(" STRUCTURES AND UNIONS IN C\n");
 printf("==============================================\n\n");

 // Run all demonstrations
 demonstrateBasicStruct();
 demonstrateNestedStruct();
 demonstrateArrayOfStructures();
 demonstrateLinkedList();
 demonstrateUnion();
 demonstrateStructureVsUnion();

 return 0;
}

/* ============================================
 * 1. BASIC STRUCTURE OPERATIONS
 * ============================================ */

void demonstrateBasicStruct() {
 printf("=== 1. BASIC STRUCTURE OPERATIONS ===\n\n");

 // Declare structure variable
 struct Student s1;

 // Method 1: Initialize at declaration
 struct Student s2 = {102, "Priya", 91.5};

 // Method 2: Designated initializers (C99)
 struct Student s3 = {.name = "Karthik", .usn = 103, .percentage = 88.0};

 // Assign values using dot operator
 s1.usn = 101;
 strcpy(s1.name, "Rahul");
 s1.percentage = 85.5;

 // Display using arrow operator with pointer
 struct Student *ptr = &s1;
 printf("Using dot operator (.):\n");
 printf(" USN: %d, Name: %s, Percentage: %.2f\n\n", 
 s1.usn, s1.name, s1.percentage);

 printf("Using arrow operator (->):\n");
 printf(" USN: %d, Name: %s, Percentage: %.2f\n\n", 
 ptr->usn, ptr->name, ptr->percentage);

 printf("Pre-initialized structures:\n");
 printf(" s2: USN=%d, Name=%s, Percentage=%.2f\n", 
 s2.usn, s2.name, s2.percentage);
 printf(" s3: USN=%d, Name=%s, Percentage=%.2f\n\n", 
 s3.usn, s3.name, s3.percentage);

 // Demonstrate typedef usage
 Employee emp;
 emp.id = 1001;
 strcpy(emp.department, "Computer Science");
 emp.salary = 55000.00;

 printf("Using typedef (Employee):\n");
 printf(" ID: %d, Dept: %s, Salary: %.2f\n\n", 
 emp.id, emp.department, emp.salary);

 printf("Size of struct Student: %lu bytes\n\n", sizeof(struct Student));
}

/* ============================================
 * 2. NESTED STRUCTURES
 * ============================================ */

void demonstrateNestedStruct() {
 printf("=== 2. NESTED STRUCTURES ===\n\n");

 struct StudentWithDOB student;

 student.usn = 201;
 strcpy(student.name, "Aishwarya");
 student.percentage = 92.5;

 // Accessing nested structure members (using dot twice)
 student.dob.day = 15;
 student.dob.month = 8;
 student.dob.year = 2004;

 printf("Student Details:\n");
 printf(" USN: %d\n", student.usn);
 printf(" Name: %s\n", student.name);
 printf(" DOB: %d/%d/%d\n", 
 student.dob.day, student.dob.month, student.dob.year);
 printf(" Percentage: %.2f\n\n", student.percentage);
}

/* ============================================
 * 3. ARRAY OF STRUCTURES
 * ============================================ */

void demonstrateArrayOfStructures() {
 printf("=== 3. ARRAY OF STRUCTURES ===\n\n");

 // Array of structures - storing multiple records
 struct Student class[3] = {
 {101, "Rahul", 85.5},
 {102, "Priya", 91.2},
 {103, "Karthik", 78.9}
 };

 int n = 3;

 printf("Class Student Records:\n");
 printf("%-5s %-10s %-10s\n", "USN", "Name", "Percentage");
 printf("--------------------------------\n");

 for (int i = 0; i < n; i++) {
 printf("%-5d %-10s %-10.2f\n", 
 class[i].usn, class[i].name, class[i].percentage);
 }
 printf("\n");
}

/* ============================================
 * 4. SELF-REFERENTIAL STRUCTURE (LINKED LIST)
 * ============================================ */

void demonstrateLinkedList() {
 printf("=== 4. SELF-REFERENTIAL STRUCTURE (LINKED LIST) ===\n\n");

 // Create nodes dynamically
 struct Node *head = (struct Node *)malloc(sizeof(struct Node));
 struct Node *second = (struct Node *)malloc(sizeof(struct Node));
 struct Node *third = (struct Node *)malloc(sizeof(struct Node));

 // Check if memory allocation successful
 if (!head || !second || !third) {
 printf("Memory allocation failed!\n");
 return;
 }

 // Assign data and link nodes
 head->data = 10;
 head->next = second;

 second->data = 20;
 second->next = third;

 third->data = 30;
 third->next = NULL; // End of list

 // Traverse and print linked list
 printf("Linked List: ");
 struct Node *current = head;
 while (current != NULL) {
 printf("%d ", current->data);
 if (current->next != NULL) {
 printf("-> ");
 }
 current = current->next;
 }
 printf("-> NULL\n");

 // Memory diagram
 printf("\nMemory Layout:\n");
 printf(" head -> [data:10 | next: second]\n");
 printf(" second -> [data:20 | next: third]\n");
 printf(" third -> [data:30 | next: NULL]\n");

 // Free allocated memory
 free(head);
 free(second);
 free(third);

 printf("\nNote: Pointers have fixed size (4/8 bytes), enabling self-reference\n\n");
}

/* ============================================
 * 5. UNION DEMONSTRATION
 * ============================================ */

void demonstrateUnion() {
 printf("=== 5. UNION DEMONSTRATION ===\n\n");

 union Data d;

 printf("Initial union size: %lu bytes (largest member: int=4 bytes)\n\n", 
 sizeof(union Data));

 // Store integer
 d.i = 65;
 printf("After d.i = 65:\n");
 printf(" d.i = %d\n", d.i); // 65
 printf(" d.c = '%c' (ASCII 65)\n", d.c); // 'A' - same memory!
 printf(" d.f = %.2f (garbage)\n\n", d.f);

 // Store float - overwrites integer memory!
 d.f = 3.14;
 printf("After d.f = 3.14:\n");
 printf(" d.f = %.2f\n", d.f); // 3.14
 printf(" d.i = %d (OVERWRITTEN!)\n", d.i); // Garbage
 printf(" d.c = '%c' (OVERWRITTEN!)\n\n", d.c); // Garbage

 // Store character
 d.c = 'Z';
 printf("After d.c = 'Z':\n");
 printf(" d.c = '%c'\n", d.c); // 'Z'
 printf(" d.i = %d (ASCII of 'Z' is 90)\n", d.i); // 90
 printf(" d.f = %.2f (garbage)\n\n", d.f);
}

/* ============================================
 * 6. STRUCTURE VS UNION COMPARISON
 * ============================================ */

void demonstrateStructureVsUnion() {
 printf("=== 6. STRUCTURE VS UNION COMPARISON ===\n\n");

 // Equivalent structure
 struct DataStruct {
 int i;
 float f;
 char c;
 } s;

 // Equivalent union
 union DataUnion {
 int i;
 float f;
 char c;
 } u;

 printf("Memory Comparison:\n");
 printf(" sizeof(struct DataStruct) = %lu bytes\n", sizeof(s));
 printf(" sizeof(union DataUnion) = %lu bytes\n\n", sizeof(u));

 // Structure: all members can be used together
 printf("STRUCTURE - All members have separate memory:\n");
 s.i = 100;
 s.f = 3.14;
 s.c = 'A';
 printf(" s.i = %d, s.f = %.2f, s.c = '%c' (all valid simultaneously)\n\n", 
 s.i, s.f, s.c);

 // Union: only one member valid at a time
 printf("UNION - All members share the same memory:\n");
 u.i = 100;
 printf(" After u.i = 100: u.i = %d, u.c = '%c'\n", u.i, u.c);
 u.f = 3.14;
 printf(" After u.f = 3.14: u.i = %d (overwritten!), u.c = '%c' (overwritten!)\n\n", 
 u.i, u.c);

 printf("============================================\n");
 printf("KEY TAKEAWAYS:\n");
 printf("- Structures: All members coexist, size = sum of all\n");
 printf("- Unions: One member at a time, size = largest member\n");
 printf("- Unions save memory but need careful handling\n");
 printf("============================================\n");
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* ============================================
 * STRUCTURE DEFINITIONS
 * ============================================ */

struct Rectangle {
 int length;
 int width;
};

struct Point {
 int x;
 int y;
};

struct Circle {
 struct Point center; // Nested structure
 float radius;
};

/* ============================================
 * FUNCTION DECLARATIONS
 * ============================================ */

// Pass by value - creates a copy
void calculateAreaByValue(struct Rectangle r) {
 r.length = 100; // Only modifies local copy
 printf(" Inside byValue: Area = %d\n", r.length * r.width);
}

// Pass by reference - modifies original
void calculateAreaByReference(struct Rectangle *r) {
 r->length = 100; // Modifies original
 printf(" Inside byRef: Area = %d\n", r->length * r->width);
}

// Function returning a structure
struct Point createPoint(int x, int y) {
 struct Point p;
 p.x = x;
 p.y = y;
 return p; // Returns a copy
}

// Function returning pointer to structure (dynamic allocation)
struct Circle* createCircle(int x, int y, float r) {
 struct Circle *c = (struct Circle *)malloc(sizeof(struct Circle));
 if (c == NULL) {
 return NULL;
 }
 c->center.x = x;
 c->center.y = y;
 c->radius = r;
 return c;
}

// Function to display circle using pointer to const
void displayCircle(const struct Circle *c) {
 // c->radius = 10; // ERROR: Cannot modify const
 printf(" Circle: Center(%d, %d), Radius = %.2f\n", 
 c->center.x, c->center.y, c->radius);
}

// Function using arrow operator with nested structures
void displayComplex(const struct Circle *c) {
 // Access nested members using arrow + dot
 printf(" Complex: Center.x = %d, Center.y = %d, Radius = %.2f\n",
 c->center.x, c->center.y, c->radius);
}

/* ============================================
 * MAIN FUNCTION
 * ============================================ */

int main() {
 printf("========================================\n");
 printf(" POINTERS TO STRUCTURES IN C\n");
 printf("========================================\n\n");

 /* ========================================
 * 1. BASIC POINTER TO STRUCTURE
 * ======================================== */

 printf("=== 1. Basic Pointer to Structure ===\n\n");

 struct Rectangle rect = {10, 5};
 struct Rectangle *ptr = &rect;

 printf("Original: length=%d, width=%d\n", rect.length, rect.width);

 // Accessing members via pointer
 printf("Using (*ptr).length: %d\n", (*ptr).length);
 printf("Using ptr->length: %d\n", ptr->length);
 printf("\n");

 /* ========================================
 * 2. PASS BY VALUE VS REFERENCE
 * ======================================== */

 printf("=== 2. Pass by Value vs Reference ===\n\n");

 struct Rectangle r1 = {5, 3};
 printf("Before byValue: length=%d\n", r1.length);
 calculateAreaByValue(r1);
 printf("After byValue: length=%d (unchanged!)\n\n", r1.length);

 struct Rectangle r2 = {5, 3};
 printf("Before byRef: length=%d\n", r2.length);
 calculateAreaByReference(&r2);
 printf("After byRef: length=%d (changed!)\n\n", r2.length);

 /* ========================================
 * 3. RETURNING STRUCTURES
 * ======================================== */

 printf("=== 3. Returning Structures ===\n\n");

 struct Point p1 = createPoint(10, 20);
 printf("Created point: (%d, %d)\n\n", p1.x, p1.y);

 /* ========================================
 * 4. DYNAMICALLY ALLOCATED STRUCTURE
 * ======================================== */

 printf("=== 4. Dynamic Structure Allocation ===\n\n");

 struct Circle *myCircle = createCircle(5, 10, 3.5);
 if (myCircle != NULL) {
 printf("Created circle at address %p\n", (void*)myCircle);
 displayCircle(myCircle);
 displayComplex(myCircle);
 free(myCircle); // Important: free dynamically allocated memory
 printf("Memory freed\n\n");
 }

 /* ========================================
 * 5. ARROW OPERATOR EQUIVALENCE
 * ======================================== */

 printf("=== 5. Arrow Operator ( -> ) ===\n\n");

 // Arrow operator is syntactic sugar
 struct Circle c1 = {{0, 0}, 2.0};
 struct Circle *cPtr = &c1;

 // These are equivalent:
 (*cPtr).center.x = 5;
 cPtr->center.y = 10; // More readable!
 cPtr->radius = 4.0;

 printf("Modified circle: center(%d, %d), radius %.2f\n\n",
 cPtr->center.x, cPtr->center.y, cPtr->radius);

 /* ========================================
 * 6. CONST POINTER TO STRUCTURE
 * ======================================== */

 printf("=== 6. Const Pointer to Structure ===\n\n");

 const struct Rectangle constRect = {8, 4};
 const struct Rectangle *constPtr = &constRect;

 // constPtr->length = 10; // ERROR: Cannot modify
 printf("Read-only access: width=%d\n", constPtr->width);

 printf("\n========================================\n");
 printf("KEY POINTS:\n");
 printf("- Use -> for pointer access, . for direct access\n");
 printf("- Pass by reference (&) for efficiency with large structs\n");
 printf("- Arrow operator: ptr->member is (*ptr).member\n");
 printf("- const struct* prevents accidental modification\n");
 printf("- Always free() dynamically allocated structures\n");
 printf("========================================\n");

 return 0;
}
